html: <!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Accessible Context Menu</title>
  <link rel="stylesheet" href="styles.css">
</head>
<body>
  <button id="open-menu">Open Context Menu</button>
  <div id="context-menu" role="menu" aria-hidden="true" class="context-menu">
    <ul role="menuitems" class="menu-items">
      <li role="menuitem" tabindex="-1"><button id="item1" class="menu-item">Item 1</button></li>
      <li role="menuitem" tabindex="-1"><button id="item2" class="menu-item">Item 2</button></li>
      <li role="menuitem" tabindex="-1"><button id="item3" class="menu-item">Item 3</button></li>
      <li role="menuitem" tabindex="-1"><button id="close-menu" class="menu-item close-menu">Close</button></li>
    </ul>
  </div>
  <script src="script.js"></script>
</body>
</html>
css: .context-menu {
  display: none;
  position: absolute;
  background-color: #f0f0f0;
  border: 1px solid #ccc;
  padding: 10px;
  border-radius: 5px;
  z-index: 1000;
}
.context-menu.menu-open {
  display: block;
}
.context-menu ul {
  list-style: none;
  padding: 0;
  margin: 0;
}
.context-menu li {
  margin-bottom: 10px;
}
.context-menu button {
  width: 100%;
  padding: 10px;
  background-color: transparent;
  border: none;
  cursor: pointer;
}
.close-menu {
  position: absolute;
  top: 10px;
  right: 10px;
}

js: /**
    * Open the context menu on button click
    */
  document.getElementById("open-menu").addEventListener("click", function() {
    var contextMenu = document.getElementById("context-menu");
    contextMenu.setAttribute("aria-hidden", false);
    contextMenu.classList.add("menu-open");
  });

  /**
    * Close the context menu on close button click or Escape key press
    */
  var closeMenuButton = document.getElementById("close-menu");
  closeMenuButton.addEventListener("click", function() {
    var contextMenu = document.getElementById("context-menu");
    contextMenu.setAttribute("aria-hidden", true);
    contextMenu.classList.remove("menu-open");
  });

  document.addEventListener("keydown", function(e) {
    if (e.key === "Escape") {
      var contextMenu = document.getElementById("context-menu");
      contextMenu.setAttribute("aria-hidden", true);
      contextMenu.classList.remove("menu-open");
    }
  });
  // Listen for clicks outside the menu
  document.addEventListener("click", function(e) {
    if (!e.target.closest("button#open-menu") && !e.target.closest("div#context-menu")) {
      var contextMenu = document.getElementById("context-menu");
      contextMenu.setAttribute("aria-hidden", true);
      contextMenu.classList.remove("menu-open");
    }
  });
